+
+      const [hasView, hasDismiss, hasWarn, hasRemove] = await Promise.all([
+        viewBtn.isVisible().catch(() => false),
+        dismissBtn.isVisible().catch(() => false),
+        warnBtn.isVisible().catch(() => false),
+        removeBtn.isVisible().catch(() => false),
